svg.script:
var svgRoot = document.getElementById('svgRoot');
var cx = 600, cy = 380;
var numPoints = 32;
var state = { tension: 0.5, speed: 2.0, progress: 0, playing: false, activeLayer: 0 };

var libColors = ["#00f2ff", "#ff0055", "#ffc107", "#238636", "#8957e5", "#f85149"];
var colorIdx = 0;
function getColor() { return libColors[colorIdx++ % libColors.length]; }

function createSVGEl(tag, attrs) {
var el = document.createElementNS('http://www.w3.org/2000/svg', tag);
for (var key in attrs) { el.setAttribute(key, attrs[key]); }
return el;
}

function generateCirclePath() { return "M 150 0 A 150 150 0 1 1 -150 0 A 150 150 0 1 1 150 0"; }
function generateSquarePath() { return "M -140 -140 L 140 -140 L 140 140 L -140 140 Z"; }
function generateTrianglePath() { return "M 0 -150 L 150 120 L -150 120 Z"; }
function generateHeartPath() { return "M 0 60 C -100 0 -130 -70 -70 -120 C -40 -150 -10 -130 0 -100 C 10 -130 40 -150 70 -120 C 130 -70 100 0 0 60 Z"; }
function generateHexagonPath() {
var d = "M 150 0 ";
for(var i=1; i<=6; i++){ var a = (i * 60) * Math.PI / 180; d += "L " + (150 * Math.cos(a)).toFixed(2) + " " + (150 * Math.sin(a)).toFixed(2) + " "; }
    return d + "Z";
    }
    function generateStarPath() {
    var d = "M 0 -150 ";
    for(var i=1; i<=10; i++){ var r = (i % 2 === 0) ? 150 : 60; var a = (i * 36 - 90) * Math.PI / 180; d += "L " + (r * Math.cos(a)).toFixed(2) + " " + (r * Math.sin(a)).toFixed(2) + " "; }
        return d + "Z";
        }

        function samplePath(d, num) {
        var tempPath = createSVGEl('path', {d: d});
        svgRoot.appendChild(tempPath);
        var len = tempPath.getTotalLength();
        var points = [];
        if (len === 0) len = 1;
        for(var i=0; i<num; i++) { points.push(tempPath.getPointAtLength((i / num) * len)); }
            svgRoot.removeChild(tempPath);
            return points;
            }

            function normalizePoints(points) {
            var minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
            for(var i=0; i<points.length; i++) {
                if(points[i].x < minX) minX = points[i].x;
                    if(points[i].x > maxX) maxX = points[i].x;
                    if(points[i].y < minY) minY = points[i].y;
                        if(points[i].y > maxY) maxY = points[i].y;
                        }
                        var cx2 = (minX + maxX) / 2, cy2 = (minY + maxY) / 2;
                        var scale = 280 / Math.max(maxX - minX, maxY - minY);
                        if(scale === Infinity || isNaN(scale)) scale = 1;
                        var normalized = [];
                        for(var i=0; i<points.length; i++) { normalized.push({ x: cx + (points[i].x - cx2) * scale, y: cy + (points[i].y - cy2) * scale }); }
                            return normalized;
                            }

                            var waypoints = [
                            { pts: normalizePoints(samplePath(generateCirclePath(), numPoints)), color: getColor(), dur: 1.0, tx: 0, ty: 0 },
                            { pts: normalizePoints(samplePath(generateStarPath(), numPoints)), color: getColor(), dur: 1.0, tx: 0, ty: 0 }
                            ];

                            function getBezierPath(points, tension) {
                            var path = "M " + points[0].x.toFixed(2) + "," + points[0].y.toFixed(2) + " ";
                            var n = points.length;
                            for (var i = 0; i < n; i++) {
                                var p0 = points[(i - 1 + n) % n], p1 = points[i], p2 = points[(i + 1) % n], p3 = points[(i + 2) % n];
                                var c1x = p1.x + (p2.x - p0.x) / 6 * tension * 2, c1y = p1.y + (p2.y - p0.y) / 6 * tension * 2;
                                var c2x = p2.x - (p3.x - p1.x) / 6 * tension * 2, c2y = p2.y - (p3.y - p1.y) / 6 * tension * 2;
                                path += "C " + c1x.toFixed(2) + "," + c1y.toFixed(2) + " " + c2x.toFixed(2) + "," + c2y.toFixed(2) + " " + p2.x.toFixed(2) + "," + p2.y.toFixed(2) + " ";
                                }
                                return path + "Z";
                                }

                                function lerp(p1, p2, t) { return p1 + (p2 - p1) * t; }
                                function hexToRgb(hex) {
                                if (hex.indexOf('#') !== 0) return { r: 255, g: 255, b: 255 };
                                if (hex.length === 4) hex = '#' + hex[1] + hex[1] + hex[2] + hex[2] + hex[3] + hex[3];
                                return { r: parseInt(hex.slice(1, 3), 16), g: parseInt(hex.slice(3, 5), 16), b: parseInt(hex.slice(5, 7), 16) };
                                }
                                function parseColor(c) {
                                if (!c) return { r: 255, g: 255, b: 255 };
                                if (c.indexOf('rgb') === 0) { var match = c.match(/\d+/g); return { r: parseInt(match[0]), g: parseInt(match[1]), b: parseInt(match[2]) }; }
                                return hexToRgb(c);
                                }
                                function lerpColor(c1, c2, t) {
                                var r1 = parseColor(c1), r2 = parseColor(c2);
                                return "rgb(" + Math.round(lerp(r1.r, r2.r, t)) + "," + Math.round(lerp(r1.g, r2.g, t)) + "," + Math.round(lerp(r1.b, r2.b, t)) + ")";
                                }

                                function getTotalTime() {
                                var total = 0;
                                for(var i=0; i<waypoints.length-1; i++) total += waypoints[i].dur;
                                    return Math.max(0.1, total);
                                    }
                                    function getTimes() {
                                    var times = [0];
                                    var total = getTotalTime();
                                    var current = 0;
                                    for(var i=0; i<waypoints.length-1; i++) { current += waypoints[i].dur; times.push(current / total); }
                                        if(times[times.length-1] > 1) times[times.length-1] = 1;
                                        return times;
                                        }

                                        function getCurrentMorph() {
                                        if (waypoints.length === 0) return { pts: [], color: "#000000", tx: 0, ty: 0 };
                                        if (waypoints.length === 1) {
                                        var w = waypoints[0];
                                        var pts1 = [];
                                        for(var i=0; i<w.pts.length; i++) { pts1.push({ x: w.pts[i].x + w.tx, y: w.pts[i].y + w.ty }); }
                                            return { pts: pts1, color: w.color, tx: w.tx, ty: w.ty };
                                            }
                                            var times = getTimes();
                                            var segIdx = 0;
                                            for(var i=0; i<times.length-1; i++) { if (state.progress >= times[i] && state.progress <= times[i+1]) { segIdx = i; break; } }
                                                    if (state.progress >= 1) segIdx = times.length - 2;

                                                    var t1 = times[segIdx], t2 = times[segIdx + 1];
                                                    var localT = (t2 === t1) ? 0 : (state.progress - t1) / (t2 - t1);
                                                    localT = Math.max(0, Math.min(1, localT));
                                                    localT = localT * localT * (3 - 2 * localT);

                                                    var w1 = waypoints[segIdx], w2 = waypoints[segIdx + 1];
                                                    var tx = lerp(w1.tx, w2.tx, localT), ty = lerp(w1.ty, w2.ty, localT);
                                                    var currentPts = [];
                                                    for(var i=0; i<w1.pts.length; i++) { currentPts.push({ x: lerp(w1.pts[i].x, w2.pts[i].x, localT) + tx, y: lerp(w1.pts[i].y, w2.pts[i].y, localT) + ty }); }
                                                        var currentColor = lerpColor(w1.color, w2.color, localT);
                                                        return { pts: currentPts, color: currentColor, tx: tx, ty: ty };
                                                        }

                                                        function update() {
                                                        if(waypoints.length === 0) { document.getElementById('morphShape').setAttribute('d', ''); return; }
                                                        var currentMorph = getCurrentMorph();
                                                        var d = getBezierPath(currentMorph.pts, state.tension);
                                                        document.getElementById('morphShape').setAttribute('d', d);
                                                        document.getElementById('morphShape').setAttribute('fill', currentMorph.color);
                                                        document.getElementById('timelineKnob').setAttribute('cx', String(450 + (state.progress * 700)));
                                                        document.getElementById('progressVal').textContent = Math.round(state.progress * 100) + '%';
                                                        }

                                                        function updateTimelineUI() {
                                                        var markers = document.getElementById('timelineMarkers');
                                                        while(markers.firstChild) markers.removeChild(markers.firstChild);
                                                        var times = getTimes();
                                                        if (times.length <= 1) return;
                                                            for(var i=1; i<times.length; i++) {
                                                                markers.appendChild(createSVGEl('line', {x1: String(450 + times[i] * 700), y1: '740', x2: String(450 + times[i] * 700), y2: '760', stroke: '#00f2ff', 'stroke-width': '2'}));
                                                                }
                                                                }

                                                                function updateLayerList() {
                                                                var list = document.getElementById('layerList');
                                                                while(list.firstChild) list.removeChild(list.firstChild);
                                                                var times = getTimes();
                                                                for(var i=0; i<waypoints.length; i++) {
                                                                    var yPos = 90 + i * 35;
                                                                    var bg = createSVGEl('rect', {x: '185', y: String(yPos), width: '320', height: '30', rx: '4', fill: (i === state.activeLayer) ? '#1f6feb' : '#21262d', style: 'cursor:pointer'});
                                                                    bg.addEventListener('click', (function(index, t) {
                                                                    return function() {
                                                                    state.activeLayer = index;
                                                                    state.progress = t;
                                                                    updateLayerList();
                                                                    updateTimelineUI();
                                                                    update();
                                                                    };
                                                                    })(i, times[i]));
                                                                    list.appendChild(bg);

                                                                    list.appendChild(createSVGEl('rect', {x: '195', y: String(yPos + 5), width: '20', height: '20', rx: '3', fill: waypoints[i].color, stroke: '#000', 'stroke-width': '1', pointerEvents: 'none'}));
                                                                    var txt = createSVGEl('text', {x: '225', y: String(yPos + 20), fill: '#c9d1d9', 'font-size': '12', pointerEvents: 'none'});
                                                                    txt.textContent = "Calque " + (i+1);
                                                                    list.appendChild(txt);

                                                                    // Boutons Durée
                                                                    if(i < waypoints.length - 1) {
                                                                        var btnMin = createSVGEl('g', {style: 'cursor:pointer;'});
                                                                        btnMin.appendChild(createSVGEl('rect', {x: '300', y: String(yPos), width: '20', height: '15', rx: '3', fill: '#30363d'}));
                                                                        var minTxt = createSVGEl('text', {x: '310', y: String(yPos+12), 'font-size': '12', fill: '#fff', 'text-anchor': 'middle', pointerEvents: 'none'});
                                                                        minTxt.textContent = '-'; btnMin.appendChild(minTxt);
                                                                        btnMin.addEventListener('click', (function(index){ return function(e) { e.stopPropagation(); waypoints[index].dur += 0.5; updateLayerList(); updateTimelineUI(); update(); }; })(i));
                                                                        list.appendChild(btnMin);

                                                                        var durTxt = createSVGEl('text', {x: '335', y: String(yPos+12), 'font-size': '10', fill:'#00f2ff', 'text-anchor': 'middle', pointerEvents: 'none'});
                                                                        durTxt.textContent = waypoints[i].dur.toFixed(1) + 's';
                                                                        list.appendChild(durTxt);

                                                                        var btnPlus = createSVGEl('g', {style: 'cursor:pointer;'});
                                                                        btnPlus.appendChild(createSVGEl('rect', {x: '350', y: String(yPos), width: '20', height: '15', rx: '3', fill: '#30363d'}));
                                                                        var plusTxt = createSVGEl('text', {x: '360', y: String(yPos+12), 'font-size': '12', fill: '#fff', 'text-anchor': 'middle', pointerEvents: 'none'});
                                                                        plusTxt.textContent = '+'; btnPlus.appendChild(plusTxt);
                                                                        btnPlus.addEventListener('click', (function(index){ return function(e) { e.stopPropagation(); waypoints[index].dur = Math.max(0.1, waypoints[index].dur - 0.5); updateLayerList(); updateTimelineUI(); update(); }; })(i));
                                                                        list.appendChild(btnPlus);
                                                                        }

                                                                        // Ordre et Suppression
                                                                        if(i > 0) {
                                                                        var btnUp = createSVGEl('g', {style: 'cursor:pointer;'});
                                                                        btnUp.appendChild(createSVGEl('rect', {x: '390', y: String(yPos), width: '20', height: '15', rx: '3', fill: '#30363d'}));
                                                                        var upTxt = createSVGEl('text', {x: '400', y: String(yPos+12), 'font-size': '10', fill: '#fff', 'text-anchor': 'middle', pointerEvents: 'none'});
                                                                        upTxt.textContent = '▲'; btnUp.appendChild(upTxt);
                                                                        btnUp.addEventListener('click', (function(index){ return function(e) { e.stopPropagation(); var t = waypoints[index]; waypoints[index] = waypoints[index-1]; waypoints[index-1] = t; updateLayerList(); updateTimelineUI(); update(); }; })(i));
                                                                        list.appendChild(btnUp);
                                                                        }
                                                                        if(i < waypoints.length - 1) {
                                                                            var btnDown = createSVGEl('g', {style: 'cursor:pointer;'});
                                                                            btnDown.appendChild(createSVGEl('rect', {x: '415', y: String(yPos), width: '20', height: '15', rx: '3', fill: '#30363d'}));
                                                                            var dwnTxt = createSVGEl('text', {x: '425', y: String(yPos+12), 'font-size': '10', fill: '#fff', 'text-anchor': 'middle', pointerEvents: 'none'});
                                                                            dwnTxt.textContent = '▼'; btnDown.appendChild(dwnTxt);
                                                                            btnDown.addEventListener('click', (function(index){ return function(e) { e.stopPropagation(); var t = waypoints[index]; waypoints[index] = waypoints[index+1]; waypoints[index+1] = t; updateLayerList(); updateTimelineUI(); update(); }; })(i));
                                                                            list.appendChild(btnDown);
                                                                            }
                                                                            var btnDel = createSVGEl('g', {style: 'cursor:pointer;'});
                                                                            btnDel.appendChild(createSVGEl('rect', {x: '440', y: String(yPos), width: '20', height: '15', rx: '3', fill: '#da3633'}));
                                                                            var delTxt = createSVGEl('text', {x: '450', y: String(yPos+12), 'font-size': '10', fill: '#fff', 'text-anchor': 'middle', pointerEvents: 'none'});
                                                                            delTxt.textContent = '✕'; btnDel.appendChild(delTxt);
                                                                            btnDel.addEventListener('click', (function(index){ return function(e) { e.stopPropagation(); waypoints.splice(index, 1); if(state.activeLayer >= waypoints.length) state.activeLayer = waypoints.length-1; updateLayerList(); updateTimelineUI(); update(); }; })(i));
                                                                            list.appendChild(btnDel);
                                                                            }
                                                                            }

                                                                            function closeAllMenus() {
                                                                            document.getElementById('panel_files').style.display = 'none';
                                                                            document.getElementById('panel_edit').style.display = 'none';
                                                                            document.getElementById('panel_view').style.display = 'none';
                                                                            }
                                                                            function toggleMenu(panelId) {
                                                                            var p = document.getElementById(panelId);
                                                                            var isVisible = (p.style.display === 'block');
                                                                            closeAllMenus();
                                                                            if(!isVisible) { p.style.display = 'block'; if(panelId === 'panel_view') updateLayerList(); }
                                                                            }
                                                                            document.getElementById('menu_files_btn').addEventListener('click', function() { toggleMenu('panel_files'); });
                                                                            document.getElementById('menu_edit_btn').addEventListener('click', function() { toggleMenu('panel_edit'); });
                                                                            document.getElementById('menu_view_btn').addEventListener('click', function() { toggleMenu('panel_view'); });
                                                                            window.addEventListener('mousedown', function(e) {
                                                                            var t = e.target;
                                                                            if (t.closest && (t.closest('#panel_files') || t.closest('#panel_edit') || t.closest('#panel_view') || t.closest('#menu_files_btn') || t.closest('#menu_edit_btn') || t.closest('#menu_view_btn'))) return;
                                                                            closeAllMenus();
                                                                            });

                                                                            function addShape(pathFunc, color) {
                                                                            try {
                                                                            var d = pathFunc();
                                                                            if (!d || d.trim() === '') return;
                                                                            var pts = normalizePoints(samplePath(d, numPoints));
                                                                            if (pts.length === 0) return;
                                                                            waypoints.push({ pts: pts, color: color || getColor(), dur: 1.0, tx: 0, ty: 0 });
                                                                            state.activeLayer = waypoints.length - 1;
                                                                            updateTimelineUI(); updateLayerList(); update();
                                                                            } catch(e) { console.error("Path invalide", e); }
                                                                            }

                                                                            document.getElementById('add_circle').addEventListener('click', function() { addShape(generateCirclePath); });
                                                                            document.getElementById('add_star').addEventListener('click', function() { addShape(generateStarPath); });
                                                                            document.getElementById('add_square').addEventListener('click', function() { addShape(generateSquarePath); });
                                                                            document.getElementById('add_triangle').addEventListener('click', function() { addShape(generateTrianglePath); });
                                                                            document.getElementById('add_heart').addEventListener('click', function() { addShape(generateHeartPath); });
                                                                            document.getElementById('add_hexagon').addEventListener('click', function() { addShape(generateHexagonPath); });

                                                                            document.getElementById('btn_file_input').addEventListener('click', function() { document.getElementById('fileInput').click(); });
                                                                            document.getElementById('fileInput').addEventListener('change', function(e) {
                                                                            var files = e.target.files;
                                                                            for(var i=0; i<files.length; i++) {
                                                                                var reader = new FileReader();
                                                                                reader.onload = (function(file) {
                                                                                return function(ev) {
                                                                                try {
                                                                                var txt = ev.target.result;
                                                                                var parser = new DOMParser();
                                                                                var doc = parser.parseFromString(txt, "image/svg+xml");
                                                                                var p = doc.querySelector('path');
                                                                                if(p && p.getAttribute('d')) { var d = p.getAttribute('d'); addShape(function() { return d; }); }
                                                                                } catch(err) { console.error("Erreur", err); }
                                                                                };
                                                                                })(files[i]);
                                                                                reader.readAsText(files[i]);
                                                                                }
                                                                                e.target.value = "";
                                                                                });

                                                                                document.getElementById('btn_add_custom').addEventListener('click', function() {
                                                                                var input = document.getElementById('pathInput');
                                                                                if(input && input.value.trim() !== '') { addShape(function() { return input.value.trim(); }); input.value = ''; }
                                                                                });

                                                                                document.getElementById('btn_export').addEventListener('click', function() {
                                                                                if(waypoints.length < 2) return;
                                                                                    var dValues = "", fillValues = "", keyTimesStr = "";
                                                                                    var times = getTimes();
                                                                                    for(var i=0; i<waypoints.length; i++) {
                                                                                        var pts = waypoints[i].pts, tx = waypoints[i].tx || 0, ty = waypoints[i].ty || 0;
                                                                                        var shiftedPts = [];
                                                                                        for(var j=0; j<pts.length; j++) { shiftedPts.push({ x: pts[j].x + tx, y: pts[j].y + ty }); }
                                                                                            dValues += getBezierPath(shiftedPts, state.tension) + ";";
                                                                                            fillValues += waypoints[i].color + ";";
                                                                                            keyTimesStr += times[i].toFixed(3) + ";";
                                                                                            }
                                                                                            dValues = dValues.slice(0, -1); fillValues = fillValues.slice(0, -1); keyTimesStr = keyTimesStr.slice(0, -1);
                                                                                            var keySplines = "";
                                                                                            for(var i=0; i<waypoints.length - 1; i++) { keySplines += "0.4 0 0.2 1;"; }
                                                                                                keySplines = keySplines.slice(0, -1);

                                                                                                var firstD = getBezierPath(shiftedPts, state.tension); // Approx for first, will be overwritten below
                                                                                                var firstShifted = [];
                                                                                                for(var j=0; j<waypoints[0].pts.length; j++) { firstShifted.push({ x: waypoints[0].pts[j].x + waypoints[0].tx, y: waypoints[0].pts[j].y + waypoints[0].ty }); }
                                                                                                    firstD = getBezierPath(firstShifted, state.tension);

                                                                                                    var dur = getTotalTime().toFixed(2);

                                                                                                    var smilContent = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1200 800">\n';
                                                                                                        smilContent += '  <path d="'+firstD+'" fill="'+waypoints[0].color+'" stroke="#fff" stroke-width="2">\n';
                                                                                                            smilContent += '    <animate attributeName="d" dur="'+dur+'s" repeatCount="indefinite" values="'+dValues+'" keyTimes="'+keyTimesStr+'" calcMode="spline" keySplines="'+keySplines+'" />\n';
                                                                                                            smilContent += '    <animate attributeName="fill" dur="'+dur+'s" repeatCount="indefinite" values="'+fillValues+'" keyTimes="'+keyTimesStr+'" calcMode="linear" />\n';
                                                                                                            smilContent += '  </path>\n</svg>';

                                                                                                    var blob = new Blob([smilContent], {type: "image/svg+xml;charset=utf-8"});
                                                                                                    var url = URL.createObjectURL(blob);
                                                                                                    var a = document.createElementNS('http://www.w3.org/1999/xhtml', 'a');
                                                                                                    a.href = url; a.download = "morph-animation.svg"; a.style.display = 'none';
                                                                                                    svgRoot.appendChild(a); a.click();
                                                                                                    setTimeout(function() { svgRoot.removeChild(a); URL.revokeObjectURL(url); }, 100);
                                                                                                    });

                                                                                                    document.getElementById('btn_clear').addEventListener('click', function() { waypoints = []; state.activeLayer = -1; updateTimelineUI(); updateLayerList(); update(); });

                                                                                                    // Sliders
                                                                                                    var activeSlider = null;
                                                                                                    function getSVGPoint(clientX, clientY) { var pt = svgRoot.createSVGPoint(); pt.x = clientX; pt.y = clientY; return pt.matrixTransform(svgRoot.getScreenCTM().inverse()); }
                                                                                                    document.getElementById('tensionTrack').addEventListener('mousedown', function() { activeSlider = 'tension'; });
                                                                                                    document.getElementById('speedTrack').addEventListener('mousedown', function() { activeSlider = 'speed'; });
                                                                                                    window.addEventListener('mousemove', function(e) {
                                                                                                    if(!activeSlider) return;
                                                                                                    var svgP = getSVGPoint(e.clientX, e.clientY);
                                                                                                    if(activeSlider === 'tension') {
                                                                                                    var x = svgP.x - 105; if(x<0) x=0; if(x>250) x=250;
                                                                                                        state.tension = (x / 250) * 1.0;
                                                                                                        document.getElementById('tensionKnob').setAttribute('cx', String(105 + x));
                                                                                                        document.getElementById('tensionVal').textContent = state.tension.toFixed(2);
                                                                                                        update();
                                                                                                        } else if(activeSlider === 'speed') {
                                                                                                        var x = svgP.x - 105; if(x<0) x=0; if(x>250) x=250;
                                                                                                            state.speed = 0.1 + (x / 250) * 9.9;
                                                                                                            document.getElementById('speedKnob').setAttribute('cx', String(105 + x));
                                                                                                            document.getElementById('speedVal').textContent = state.speed.toFixed(1) + "x";
                                                                                                            }
                                                                                                            });
                                                                                                            window.addEventListener('mouseup', function() { activeSlider = null; });

                                                                                                            // Timeline
                                                                                                            var timelineTrack = document.getElementById('timelineTrack');
                                                                                                            var isDraggingTimeline = false;
                                                                                                            timelineTrack.addEventListener('mousedown', function(e) { isDraggingTimeline = true; movePlayhead(e); });
                                                                                                            window.addEventListener('mousemove', function(e) { if(isDraggingTimeline) movePlayhead(e); });
                                                                                                            window.addEventListener('mouseup', function() { isDraggingTimeline = false; });
                                                                                                            function movePlayhead(e) {
                                                                                                            var svgP = getSVGPoint(e.clientX, e.clientY);
                                                                                                            var x = svgP.x - 450; if (x < 0) x = 0; if (x > 700) x = 700;
                                                                                                                setProgress(x / 700);
                                                                                                                }
                                                                                                                function setProgress(p) { state.progress = Math.max(0, Math.min(1, p)); update(); }

                                                                                                                // Viewport Drag (Translation)
                                                                                                                var isDraggingShape = false;
                                                                                                                var dragStartX, dragStartY, startTx, startTy;
                                                                                                                document.getElementById('viewportDrag').addEventListener('mousedown', function(e) {
                                                                                                                if (state.activeLayer >= 0 && state.activeLayer < waypoints.length) {
                                                                                                                    isDraggingShape = true;
                                                                                                                    var pt = getSVGPoint(e.clientX, e.clientY);
                                                                                                                    dragStartX = pt.x; dragStartY = pt.y;
                                                                                                                    startTx = waypoints[state.activeLayer].tx || 0;
                                                                                                                    startTy = waypoints[state.activeLayer].ty || 0;
                                                                                                                    document.getElementById('viewportDrag').style.cursor = 'grabbing';
                                                                                                                    }
                                                                                                                    });
                                                                                                                    window.addEventListener('mousemove', function(e) {
                                                                                                                    if (isDraggingShape) {
                                                                                                                    var pt = getSVGPoint(e.clientX, e.clientY);
                                                                                                                    waypoints[state.activeLayer].tx = startTx + (pt.x - dragStartX);
                                                                                                                    waypoints[state.activeLayer].ty = startTy + (pt.y - dragStartY);
                                                                                                                    update();
                                                                                                                    }
                                                                                                                    });
                                                                                                                    window.addEventListener('mouseup', function() {
                                                                                                                    if (isDraggingShape) {
                                                                                                                    isDraggingShape = false;
                                                                                                                    document.getElementById('viewportDrag').style.cursor = 'grab';
                                                                                                                    }
                                                                                                                    });

                                                                                                                    document.getElementById('btn_play').addEventListener('click', function() {
                                                                                                                    state.playing = !state.playing;
                                                                                                                    var txt = document.getElementById('btn_play_txt');
                                                                                                                    if(state.playing) { txt.textContent = "⏸ PAUSE"; animateLoop(); } else { txt.textContent = "▶ PLAY"; }
                                                                                                                    });

                                                                                                                    document.getElementById('btn_add_key').addEventListener('click', function() {
                                                                                                                    var currentMorph = getCurrentMorph();
                                                                                                                    if (currentMorph.pts.length === 0) return;
                                                                                                                    var insertIdx;
                                                                                                                    if (waypoints.length === 0) insertIdx = 0;
                                                                                                                    else if (waypoints.length === 1) insertIdx = 1;
                                                                                                                    else {
                                                                                                                    var times = getTimes();
                                                                                                                    var segIdx = 0;
                                                                                                                    for(var i=0; i<times.length-1; i++) { if (state.progress >= times[i] && state.progress <= times[i+1]) { segIdx = i; break; } }
                                                                                                                            insertIdx = segIdx + 1;
                                                                                                                            }
                                                                                                                            if (insertIdx > waypoints.length) insertIdx = waypoints.length;

                                                                                                                            var relativePts = [];
                                                                                                                            for(var i=0; i<currentMorph.pts.length; i++) { relativePts.push({ x: currentMorph.pts[i].x - currentMorph.tx, y: currentMorph.pts[i].y - currentMorph.ty }); }

                                                                                                                                waypoints.splice(insertIdx, 0, { pts: relativePts, color: currentMorph.color, dur: 1.0, tx: currentMorph.tx, ty: currentMorph.ty });
                                                                                                                                state.activeLayer = insertIdx;
                                                                                                                                state.progress = getTimes()[insertIdx];
                                                                                                                                updateTimelineUI(); updateLayerList(); update();
                                                                                                                                });

                                                                                                                                document.getElementById('btn_del_key').addEventListener('click', function() {
                                                                                                                                if (waypoints.length <= 1) return;
                                                                                                                                    var times = getTimes();
                                                                                                                                    var minDist = 999, closestIdx = 0;
                                                                                                                                    for(var i=0; i<times.length; i++) { var d = Math.abs(state.progress - times[i]); if(d<minDist){minDist=d; closestIdx=i;} }
                                                                                                                                            if (closestIdx >= 0 && closestIdx < waypoints.length) {
                                                                                                                                                waypoints.splice(closestIdx, 1);
                                                                                                                                                if (state.activeLayer >= waypoints.length) state.activeLayer = waypoints.length - 1;
                                                                                                                                                if (waypoints.length > 1) state.progress = 0;
                                                                                                                                                updateTimelineUI(); updateLayerList(); update();
                                                                                                                                                }
                                                                                                                                                });

                                                                                                                                                var animDir = 1;
                                                                                                                                                function animateLoop() {
                                                                                                                                                if(!state.playing) return;
                                                                                                                                                var delta = (0.01 * state.speed) / getTotalTime();
                                                                                                                                                state.progress += delta * animDir;
                                                                                                                                                if(state.progress >= 1) { state.progress = 1; animDir = -1; }
                                                                                                                                                if(state.progress <= 0) { state.progress = 0; animDir = 1; }
                                                                                                                                                    setProgress(state.progress);
                                                                                                                                                    requestAnimationFrame(animateLoop);
                                                                                                                                                    }

                                                                                                                                                    document.getElementById('speedKnob').setAttribute('cx', String(105 + ((state.speed - 0.1) / 9.9) * 250));
                                                                                                                                                    updateTimelineUI(); updateLayerList(); update();
